def pos(n):
    return [i+1 for i,b in enumerate(bin(n)[:1:-1]) if b=='1']
seq = []
best = 0
n = 1
while len(seq) < 20:
    p = pos(n)
    s = {x+y for x in p for y in p}
    evens = sorted([x for x in s if x%2==0])
    if evens and evens == list(range(2, evens[-1]+1, 2)):
        if len(evens) > best:
            best = len(evens)
            seq.append(n)
    n += 1
print(seq)

